      if(U.isValid(d.numCPU)&&d.memSizeB) vmwRows.push(['vCPU / RAM', d.numCPU+' · '+U.fmtBytes(d.memSizeB)]);
      var vmwHtml='';
      if(vmwRows.length>0){
        vmwHtml='<div class="ks-vmw-grid">'
          +vmwRows.map(function(r){
