        + (desc || timeStr || urlHtml
          ? '<div class="kt-row-bottom">'
              + (desc ? '<span class="kt-desc" title="' + U.esc(desc) + '">' + U.esc(U.trunc(desc, 100)) + '</span>' : '')
              + '<span class="kt-time">' + U.esc(timeStr) + '</span>'
              + urlHtml
            + '</div>'
          : '')

        + '</div>';
    },
  };


