      return ZbxApi.call('trigger.get', {
        hostids:         [hostid],
        output:          ['triggerid', 'description', 'priority', 'lastchange',
                          'value', 'comments', 'url', 'status'],
        selectLastEvent: ['clock', 'name', 'value', 'eventid'],
        selectItems:     ['itemid', 'name', 'lastvalue', 'units'],
        monitored:       true,
