  var SVG = {

    sourceBadge: function (source, hasAgent) {
      if (hasAgent) {
        return '<span class="kc3-badge agente">AGENTE</span>';
      }
      if (source === 'VMware') {
        return '<span class="kc3-badge no-agent">SEM AGENTE</span>'
             + '<span class="kc3-badge vmware" style="margin-left:4px;">VMware</span>';
      }
      return '<span class="kc3-badge no-agent">SEM AGENTE</span>';
